const e=JSON.parse('{"key":"v-3ac1e238","path":"/basics/MySQL/interview/5_%E9%94%81.html","title":"锁","lang":"zh-CN","frontmatter":{"summary":"锁 事务并发访问同一数据资源的情况主要就分为读-读、写-写和读-写三种。 1. 读-读 即并发事务同时访问同一行数据记录。由于两个事务都进行只读操作，不会对记录造成任何影响，因此并发读完全允许。 2. 写-写 即并发事务同时修改同一行数据记录。这种情况下可能导致脏写问题，这是任何情况下都不允许发生的，因此只能通过加锁实现，也就是当一个事务需要对某行记录进行修","head":[["meta",{"property":"og:url","content":"https://vuepress-theme-hope-v2-demo.mrhope.site/basics/MySQL/interview/5_%E9%94%81.html"}],["meta",{"property":"og:site_name","content":"Weiser"}],["meta",{"property":"og:title","content":"锁"}],["meta",{"property":"og:type","content":"article"}],["meta",{"property":"og:updated_time","content":"2022-09-05T07:38:43.000Z"}],["meta",{"property":"og:locale","content":"zh-CN"}],["meta",{"property":"article:modified_time","content":"2022-09-05T07:38:43.000Z"}]]},"excerpt":"","headers":[{"level":2,"title":"锁的分类","slug":"锁的分类","link":"#锁的分类","children":[]},{"level":2,"title":"InnoDB中的表级锁","slug":"innodb中的表级锁","link":"#innodb中的表级锁","children":[]},{"level":2,"title":"InnoDB中的行级锁","slug":"innodb中的行级锁","link":"#innodb中的行级锁","children":[]},{"level":2,"title":"两阶段锁协议（Two-Pahse Locking -- 2PL）","slug":"两阶段锁协议-two-pahse-locking-2pl","link":"#两阶段锁协议-two-pahse-locking-2pl","children":[]}],"git":{"createdTime":1662363523000,"updatedTime":1662363523000,"contributors":[{"name":"xwzbupt","email":"xwze@bupt.cn","commits":1}]},"readingTime":{"minutes":7.89,"words":2367},"filePathRelative":"basics/MySQL/interview/5_锁.md","localizedDate":"2022年9月5日"}');export{e as data};
